
public class OperadoresIncrementales {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		// Incrementa al lado izquierdo
		
		int a = 5;
		int b = ++a;
	
		System.out.println("El valor total en a es: " + a);
		System.out.println ("El valor total en b es:" + b );
		System.out.println ("");
		
		// Incrementa al lado derecho
		int c = 5;
		int d = c++;
		System.out.println("El valor total en c es: " + c);
		System.out.println ("El valor total en d es:" + d);
		System.out.println ("");
						
		// Disminuye al lado izquierdo
		
		int e = 5;
		int f = --e;
	
		System.out.println("El valor total en a es: " + e);
		System.out.println ("El valor total en b es: " + f  );
		System.out.println ("");
		
		// Disminuye al lado derecho
		int g = 5;
		int h = g--;
		System.out.println("El valor total en c es: " + g);
		System.out.println ("El valor total en d es: " + h);
		

	}

}
